--
-- Name: cleanup_expired_oauth(); Type: FUNCTION; Schema: public; Owner: matric
--

CREATE FUNCTION public.cleanup_expired_oauth() RETURNS void
    LANGUAGE plpgsql
    AS $$
BEGIN
    -- Delete expired authorization codes
    DELETE FROM oauth_authorization_code WHERE expires_at < NOW();

    -- Delete expired tokens (keep revoked for audit for 30 days)
    DELETE FROM oauth_token
    WHERE access_token_expires_at < NOW() - INTERVAL '30 days'
      AND (refresh_token_expires_at IS NULL OR refresh_token_expires_at < NOW() - INTERVAL '30 days');

    -- Clean up old rate limit entries
    DELETE FROM rate_limit WHERE window_end < NOW();
END;
$$;


ALTER FUNCTION public.cleanup_expired_oauth() OWNER TO matric;

--
-- Name: estimate_job_duration(public.job_type, integer); Type: FUNCTION; Schema: public; Owner: matric
--

CREATE FUNCTION public.estimate_job_duration(p_job_type public.job_type, p_payload_size integer) RETURNS integer
    LANGUAGE plpgsql
    AS $$
DECLARE
    avg_duration INTEGER;
BEGIN
    SELECT COALESCE(AVG(duration_ms)::INTEGER, 5000)
    INTO avg_duration
    FROM job_history
    WHERE job_type = p_job_type
      AND success = TRUE
      AND created_at > NOW() - INTERVAL '30 days';

    RETURN avg_duration;
END;
$$;


ALTER FUNCTION public.estimate_job_duration(p_job_type public.job_type, p_payload_size integer) OWNER TO matric;

